+//		    path: path
+//	      - key: key2
+//			path: path/path2
+//
+// In such cases we either get `is directory` or 'file exists' message.
+// For projected volume we also assert that there is not overlap with service account token since that is missing in the validation processes.
+func warningsForOverlappingVirtualPaths(volumes []api.Volume) []string {
