+// Matcher is a helper for comparing field.Error objects.
+type Matcher struct {
+	matchType                bool
+	matchField               bool
+	matchValue               bool
+	matchOrigin              bool
+	matchDetail              func(want, got string) bool
+	requireOriginWhenInvalid bool
+}
